<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentHouse;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentHouseRepository extends BaseRepository{    public function __construct(StudentHouse $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?StudentHouse    {        return $this->query()->where('code', $code)->first();    }    public function findByName(string $name): ?StudentHouse    {        return $this->query()->where('name', $name)->first();    }    public function getActiveHouses(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getHouseWithMembers(int $houseId): ?StudentHouse    {        return $this->query()->with('students')->findOrFail($houseId);    }    public function countStudentsByHouse(): Collection    {        return $this->query()->withCount('students')->get();    }    public function searchHouses(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}